ValidationRule.errorConditionFormula:
AND(
    ISCHANGED(OwnerId),
    OR(
        /* System Administrator: solo necesita Lead Source */
        AND(
            $Profile.Name = 'System Administrator',
            ISBLANK(TEXT(LeadSource))
        ),
        /* Contract Manager: necesita Country y Lead Source, NO necesita No. of Employees */
        AND(
            $Profile.Name = 'Contract Manager',
            OR(
                ISBLANK(Country),
                ISBLANK(TEXT(LeadSource))
            )
        ),
        /* Resto de perfiles: necesita Country, Lead Source y No. of Employees */
        AND(
            $Profile.Name <> 'System Administrator',
            $Profile.Name <> 'Contract Manager',
            OR(
                ISBLANK(Country),
                ISBLANK(TEXT(LeadSource)),
                ISBLANK(NumberOfEmployees)
            )
        )
    )
)
